  return (
    <div>
      <div style={{ padding:'0.75rem 1rem',background:'#f0fdf4',border:'1px solid #bbf7d0',borderRadius:10,marginBottom:'1rem',fontSize:'0.82rem',color:'#15803d',display:'flex',gap:8,alignItems:'flex-start' }}>
        <I c="fa-circle-info" style={{marginTop:2,flexShrink:0}}/>
        <span>Edit the AI knowledge base directly from here — no coding needed. Changes take effect immediately. The AI analyzes symptoms against the symptoms list you set here.</span>
