      </div>

      {/* User roles */}
      <div className="card">
        <h4 style={{fontSize:'0.875rem',fontWeight:700,marginBottom:'1rem',fontFamily:'Outfit,sans-serif'}}>
          <I c="fa-users" style={{color:'#0891b2',marginRight:6}}/>User Role Distribution
