              <div style={{fontSize:'1.5rem',fontWeight:800,fontFamily:'Fraunces,serif',color:'#374151'}}>{r.count}</div>
              <div style={{fontSize:'0.75rem',color:'#6b7280',fontWeight:600}}>{r.role}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Blockchain verification */}
      <BlockchainStatus/>
    </div>
  );
}

function BlockchainStatus() {
  const [status, setStatus] = useState(null);
  const [loading, setLoading] = useState(false);

  const verify = (type) => {
    setLoading(true);
    api.get(`/api/admin/blockchain/verify?type=${type}`)
      .then(r => { setStatus(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  };

  return (
    <div className="card">
      <h4 style={{fontSize:'0.875rem',fontWeight:700,marginBottom:'1rem',fontFamily:'Outfit,sans-serif'}}>
        <I c="fa-link" style={{color:'#7c3aed',marginRight:6}}/>Blockchain Audit Chain Verification
      </h4>
      <div style={{fontSize:'0.8rem',color:'#6b7280',marginBottom:'0.75rem'}}>
        Each health record, appointment, and medication is hashed and chained for tamper-evidence. Click to verify integrity.
      </div>
      <div style={{display:'flex',gap:8,marginBottom:'0.75rem',flexWrap:'wrap'}}>
        {['analysis','appointment','medication'].map(type => (
          <button key={type} className="btn btn-outline btn-sm" onClick={()=>verify(type)} disabled={loading}>
            <I c="fa-shield-halved" style={{marginRight:4}}/>Verify {type} chain
          </button>
        ))}
      </div>
      {status && (
        <div className={`alert ${status.chain_valid?'alert-success':'alert-error'}`}>
          <strong>{status.record_type} chain:</strong> {status.total_records} records ·{' '}
          {status.chain_valid
            ? <><I c="fa-circle-check" style={{marginRight:4}}/>Chain is valid ✓</>
            : <><I c="fa-triangle-exclamation" style={{marginRight:4}}/>Chain broken at record #{status.broken_at_id}</>
          }
        </div>
      )}
    </div>
  );
}

// ── ML Status ─────────────────────────────────────────────────────────────────
function MLStatus() {
  const [info, setInfo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [training, setTraining] = useState(false);
  const [trainOutput, setTrainOutput] = useState('');

  const load = () => {
    setLoading(true);
    api.get('/api/admin/ml/status')
      .then(r => { setInfo(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  };
  useEffect(() => { load(); }, []);

  const triggerTrain = async () => {
    if (!window.confirm('This will run ml_train.py on the server. Proceed?')) return;
    setTraining(true); setTrainOutput('');
    try {
      const res = await api.post('/api/admin/ml/train');
      setTrainOutput(res.data.output || 'Training complete!');
      load();
    } catch (e) {
      setTrainOutput(e.response?.data?.output || e.response?.data?.error || 'Training failed.');
    }
    setTraining(false);
  };

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;

  return (
    <div style={{display:'flex',flexDirection:'column',gap:'1rem'}}>
      {/* Engine status */}
      <div className="card">
        <h4 style={{fontSize:'0.95rem',fontWeight:700,marginBottom:'1rem',fontFamily:'Outfit,sans-serif'}}>
          <I c="fa-robot" style={{color:'#7c3aed',marginRight:6}}/>AI Engine Status
        </h4>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:'1rem'}}>
          <div style={{padding:'0.9rem',background:info?.model_trained?'#f0fdf4':'#fff7ed',borderRadius:10,border:`1px solid ${info?.model_trained?'#bbf7d0':'#fcd34d'}`}}>
            <div style={{fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',marginBottom:4}}>Current Engine</div>
            <div style={{fontWeight:700,fontSize:'0.9rem',color:info?.model_trained?'#16a34a':'#d97706'}}>
              <I c={info?.model_trained?'fa-robot':'fa-book'} style={{marginRight:6}}/>{info?.engine}
            </div>
          </div>
          <div style={{padding:'0.9rem',background:'#f9fafb',borderRadius:10,border:'1px solid #e5e7eb'}}>
            <div style={{fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',marginBottom:4}}>Feedback Received</div>
            <div style={{fontWeight:700,fontSize:'0.9rem',color:'#374151'}}>
              {info?.feedback_total || 0} total · {info?.feedback_helpful || 0} helpful
            </div>
          </div>
        </div>

        {info?.model_trained && info?.model_info && (
          <div style={{background:'#f9fafb',borderRadius:10,padding:'0.9rem',marginBottom:'1rem',fontSize:'0.82rem',color:'#374151'}}>
            <div style={{fontWeight:700,marginBottom:6}}>Model Information</div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6}}>
              {Object.entries(info.model_info).map(([k, v]) => k !== 'error' && (
                <div key={k}><span style={{color:'#9ca3af'}}>{k.replace(/_/g,' ')}:</span> <strong>{String(v)}</strong></div>
              ))}
            </div>
          </div>
        )}

        <div style={{padding:'0.9rem',background:'#f8faff',borderRadius:10,border:'1px solid #e0e7ff',marginBottom:'1rem'}}>
          <div style={{fontWeight:700,fontSize:'0.8rem',color:'#374151',marginBottom:6}}>How the ML Engine Works</div>
          <div style={{fontSize:'0.78rem',color:'#6b7280',lineHeight:1.8}}>
            <ol style={{paddingLeft:16,margin:0}}>
              <li><strong>Training Data</strong> — Generated from deficiency knowledge base with 100 varied symptom descriptions per class</li>
              <li><strong>NLP Preprocessing</strong> — spaCy tokenization, lemmatization, stop-word removal</li>
              <li><strong>TF-IDF Vectorizer</strong> — Converts text to numerical features (unigrams + bigrams, 5000 features)</li>
              <li><strong>Multinomial Naive Bayes</strong> — Classifies symptom descriptions into deficiency categories</li>
              <li><strong>Confidence Score</strong> — Model probability converted to 20–95% range</li>
              <li><strong>Fallback</strong> — If ML fails, rule-based keyword matching is used automatically</li>
            </ol>
          </div>
        </div>

        <div style={{display:'flex',gap:8,flexWrap:'wrap'}}>
          <button className="btn btn-primary" onClick={triggerTrain} disabled={training}>
            {training ? <><span className="spinner" style={{width:16,height:16}}/> Training...</> : <><I c="fa-gear" style={{marginRight:6}}/>{info?.model_trained ? 'Retrain Model' : 'Train ML Model'}</>}
          </button>
          <button className="btn btn-ghost" onClick={load}><I c="fa-rotate" style={{marginRight:4}}/>Refresh</button>
        </div>

        {trainOutput && (
          <div style={{marginTop:'0.75rem',background:'#111827',color:'#4ade80',borderRadius:8,padding:'0.75rem',fontSize:'0.75rem',fontFamily:'monospace',whiteSpace:'pre-wrap',maxHeight:200,overflowY:'auto'}}>
            {trainOutput}
          </div>
        )}
      </div>

    </div>
  );
}

// ── Feedback ──────────────────────────────────────────────────────────────────
function FeedbackTab() {
  const [feedback, setFeedback] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/api/admin/feedback')
      .then(r => { setFeedback(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;

  const helpful = feedback.filter(f => f.helpful).length;
  const total = feedback.length;

  return (
    <div>
      {total > 0 && (
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(140px,1fr))',gap:12,marginBottom:'1rem'}}>
          {[
            {label:'Total Feedback', value:total, color:'#374151', icon:'fa-star'},
            {label:'Helpful', value:helpful, color:'#16a34a', icon:'fa-thumbs-up'},
            {label:'Not Helpful', value:total-helpful, color:'#dc2626', icon:'fa-thumbs-down'},
            {label:'Satisfaction', value:`${total>0?Math.round(helpful/total*100):0}%`, color:'#0891b2', icon:'fa-chart-line'},
          ].map(c => (
            <div key={c.label} className="card" style={{textAlign:'center',padding:'0.9rem',border:`1px solid ${c.color}15`}}>
              <I c={c.icon} style={{color:c.color,fontSize:'1.2rem',marginBottom:4,display:'block'}}/>
              <div style={{fontSize:'1.4rem',fontWeight:800,fontFamily:'Fraunces,serif',color:c.color}}>{c.value}</div>
              <div style={{fontSize:'0.68rem',color:'#6b7280',marginTop:2}}>{c.label}</div>
            </div>
          ))}
        </div>
      )}

      <div className="card">
        <h4 style={{fontSize:'0.875rem',fontWeight:700,marginBottom:'1rem',fontFamily:'Outfit,sans-serif'}}>
          <I c="fa-star" style={{color:'#d97706',marginRight:6}}/>User Feedback on AI Predictions
        </h4>
        {!feedback.length ? (
          <div style={{textAlign:'center',padding:'2rem',color:'#9ca3af'}}>No feedback received yet. Encourage users to rate AI predictions!</div>
        ) : (
          <div style={{overflowX:'auto'}}>
            <table style={{width:'100%',borderCollapse:'collapse'}}>
              <thead style={{background:'#f9fafb'}}>
                <tr>
                  {['User','Predicted','Correction','Helpful','Comment','Date'].map(h => (
                    <th key={h} style={{padding:'8px 12px',textAlign:'left',fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',borderBottom:'1px solid #e5e7eb'}}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {feedback.map(f => (
                  <tr key={f.id} style={{borderBottom:'1px solid #f1f1f1'}}>
                    <td style={{padding:'8px 12px',fontSize:'0.8rem',color:'#374151'}}>{f.user_name || 'Anonymous'}</td>
                    <td style={{padding:'8px 12px',fontSize:'0.78rem',color:'#374151'}}>{f.predicted_id || '—'}</td>
                    <td style={{padding:'8px 12px',fontSize:'0.78rem',color:'#374151'}}>{f.corrected_id || '—'}</td>
                    <td style={{padding:'8px 12px',textAlign:'center'}}>
                      <I c={f.helpful?'fa-thumbs-up':'fa-thumbs-down'} style={{color:f.helpful?'#16a34a':'#dc2626'}}/>
                    </td>
                    <td style={{padding:'8px 12px',fontSize:'0.78rem',color:'#6b7280',maxWidth:160}}>{f.comment || '—'}</td>
                    <td style={{padding:'8px 12px',fontSize:'0.72rem',color:'#9ca3af'}}>{new Date(f.timestamp).toLocaleDateString('en-KE')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

// ── Audit Logs ────────────────────────────────────────────────────────────────
function AuditLogs() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');

  useEffect(() => {
    api.get('/api/admin/audit')
      .then(r => { setLogs(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const ACTION_COLORS = {
    login:'#16a34a', login_failed:'#dc2626', register:'#0891b2',
    sos:'#dc2626', ml_train:'#7c3aed', admin_delete_user:'#dc2626',
    add_hospital:'#d97706', validate_analysis:'#0891b2',
  };

  const filtered = filter ? logs.filter(l => l.action?.includes(filter) || l.user_name?.toLowerCase().includes(filter.toLowerCase())) : logs;

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;

  return (
    <div className="card">
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',flexWrap:'wrap',gap:8}}>
        <h4 style={{fontSize:'0.95rem',fontWeight:700,fontFamily:'Outfit,sans-serif'}}>
          <I c="fa-shield-halved" style={{color:'#7c3aed',marginRight:6}}/>Audit Logs (last {logs.length})
        </h4>
        <input className="form-input" value={filter} onChange={e=>setFilter(e.target.value)}
          placeholder="Filter by action or user..." style={{width:200,padding:'0.5rem 0.75rem'}}/>
      </div>
      {!filtered.length ? (
        <div style={{textAlign:'center',padding:'2rem',color:'#9ca3af'}}>No audit logs found.</div>
      ) : (
        <div style={{overflowX:'auto'}}>
          <table style={{width:'100%',borderCollapse:'collapse'}}>
            <thead style={{background:'#f9fafb'}}>
              <tr>{['Time','User','Action','Details'].map(h=>(
                <th key={h} style={{padding:'8px 12px',textAlign:'left',fontSize:'0.7rem',fontWeight:700,color:'#6b7280',textTransform:'uppercase',borderBottom:'1px solid #e5e7eb'}}>{h}</th>
              ))}</tr>
            </thead>
            <tbody>
              {filtered.map(l => (
                <tr key={l.id} style={{borderBottom:'1px solid #f1f1f1'}}>
                  <td style={{padding:'8px 12px',fontSize:'0.72rem',color:'#9ca3af',whiteSpace:'nowrap'}}>{new Date(l.timestamp).toLocaleString('en-KE')}</td>
                  <td style={{padding:'8px 12px',fontSize:'0.8rem',color:'#374151'}}>{l.user_name || <span style={{color:'#d1d5db'}}>System</span>}</td>
                  <td style={{padding:'8px 12px'}}>
                    <span style={{background:`${ACTION_COLORS[l.action]||'#6b7280'}15`,color:ACTION_COLORS[l.action]||'#6b7280',borderRadius:6,padding:'2px 8px',fontSize:'0.72rem',fontWeight:700}}>
                      {l.action}
                    </span>
                  </td>
                  <td style={{padding:'8px 12px',fontSize:'0.78rem',color:'#6b7280',maxWidth:200,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{l.details}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ── Admin Shell ───────────────────────────────────────────────────────────────
